module top_module (
    input [1:0] r,
    output reg not_z
);

    always @(*) begin
        case (r)
            2'b00: not_z = 1;
            2'b01: not_z = 1;
            2'b10: not_z = 0;
            2'b11: not_z = 1;
            default: not_z = 0; // Default case
        endcase
    end
endmodule
